using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class PaymentsTraining : TrainingContentBase
{
    public PaymentsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payments Overview",
            Slug = "payments-overview",
            Summary = "What the Payments module does, standalone vs integrated mode, payment methods, and how payments apply to invoices.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/payments"]""",
            Tags = """["payments","accounting"]""",
            ContentJson = """{"body":"## Payments Overview\n\nThe Payments module records incoming customer payments and applies them to outstanding invoices. It is part of the accounting boundary — meaning it operates in **standalone mode** when no external accounting provider (QuickBooks, Xero, etc.) is connected. When an accounting provider is integrated, payments sync from the external system and the module becomes read-only.\n\n### Standalone vs Integrated Mode\n\n**Standalone mode (no accounting provider):** You have full control. Create payments, apply them to invoices, delete unapplied payments, and track payment history directly in QB Engineer. This is the default for shops that don't use an external accounting system.\n\n**Integrated mode (accounting provider connected):** A blue banner appears at the top of the Payments page indicating that payments are managed by the connected provider (e.g., QuickBooks Online). Payment data syncs automatically — you can view payments but cannot create, edit, or delete them from QB Engineer. All payment operations happen in the accounting system.\n\n### Payment Methods\n\nEvery payment records how it was received. The supported methods are:\n- **Cash** — physical currency received\n- **Check** — paper check (use the Reference Number field to record the check number)\n- **Credit Card** — card payment (reference number can hold the last four digits or transaction ID)\n- **Bank Transfer** — ACH or direct bank transfer\n- **Wire** — wire transfer (reference number holds the wire confirmation)\n- **Other** — any method not covered above\n\n### Applying Payments to Invoices\n\nA payment can be applied to one or more invoices. Each application specifies which invoice receives how much of the payment. This enables:\n\n- **Full payment** — the entire payment amount covers one invoice exactly\n- **Partial payment** — only part of the payment goes to an invoice (the invoice moves to Partially Paid status)\n- **Split payment** — one payment covers portions of multiple invoices\n- **Unapplied payment** — a payment (or portion of it) is recorded without being tied to any invoice yet. The unapplied amount shows in the table and is highlighted in the detail view.\n\nWhen a payment application fully covers an invoice's remaining balance, that invoice automatically moves to Paid status. If a partial amount is applied, the invoice moves to Partially Paid.\n\n### Validation Rules\n\nThe total of all applications on a payment cannot exceed the payment amount. Each individual application amount must be positive, and it cannot exceed the remaining balance on its target invoice.\n\n### When to Use Payments\n\n- When you receive a check, cash, or electronic payment from a customer\n- When you need to record a partial payment against a large invoice\n- When a single customer payment covers multiple invoices\n- When you need to track unapplied payments (money received before invoicing)\n- When reviewing payment history for a customer via the detail dialog","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payments — Guided Tour",
            Slug = "payments-walkthrough",
            Summary = "A guided tour of the payments list page: search, filters, data table, creating payments, applying to invoices, and viewing payment details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/payments"]""",
            Tags = """["payments","walkthrough","accounting"]""",
            ContentJson = """{"appRoute":"/payments","startButtonLabel":"Tour Payments","steps":[{"element":"[data-testid='new-payment-btn']","popover":{"title":"Record Payment Button","description":"Click here to record a new payment. You'll select the customer, choose a payment method, enter the amount and date, and optionally apply the payment to one or more invoices. This button is only available in standalone mode (no accounting provider connected).","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Payments","description":"Search by payment number, customer name, or reference number. Results filter in real time as you type.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Payment Method Filter","description":"Filter the table by payment method: Cash, Check, Credit Card, Bank Transfer, Wire, or Other. Select 'All Methods' to clear the filter.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Payments Table","description":"Shows all recorded payments. Columns include Payment #, Customer, Method, Amount, Applied amount, Unapplied amount (highlighted in yellow when > $0), Date, Reference #, and Created date. Click any row to open the payment detail dialog. Click column headers to sort; use the gear icon to manage column visibility.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payments Field Reference",
            Slug = "payments-field-reference",
            Summary = "Complete reference for every field, button, validation rule, payment method, and action in the Payments module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/payments"]""",
            Tags = """["payments","reference","accounting"]""",
            ContentJson = """{"title":"Payments Field Reference","groups":[{"heading":"Payment Form Fields (Create Dialog Sidebar)","items":[{"label":"Customer (required)","value":"Dropdown populated from the Customers module. Selects which customer made the payment. data-testid: payment-customer"},{"label":"Payment Method (required)","value":"Dropdown: Cash, Check, Credit Card, Bank Transfer, Wire, Other. Determines the type of payment received. data-testid: payment-method"},{"label":"Amount (required)","value":"Number input, must be greater than $0.00. The total amount of the payment received. data-testid: payment-amount"},{"label":"Payment Date (required)","value":"Date picker. The date the payment was received. Stored as UTC. data-testid: payment-date"},{"label":"Reference Number (optional)","value":"Text input. Check number, wire confirmation, transaction ID, or any external reference. data-testid: payment-ref"},{"label":"Notes (optional)","value":"Textarea, 3 rows. Free-form notes about the payment. data-testid: payment-notes"}]},{"heading":"Invoice Application Fields (Create Dialog Main Panel)","items":[{"label":"Invoice ID (required)","value":"Number input. The ID of the invoice to apply the payment against."},{"label":"Invoice Number (required)","value":"Text input. The invoice number for display purposes."},{"label":"Amount (required)","value":"Number input, must be greater than $0.00. The portion of the payment to apply to this invoice. Cannot exceed the invoice's remaining balance."},{"label":"Add button","value":"Adds the application entry to the table. Disabled when any application field is empty or invalid."},{"label":"Remove button (X icon)","value":"Removes an application entry from the table. Red danger icon button with tooltip."},{"label":"Total Applied","value":"Displayed in the applications table footer and in the sidebar summary. Sum of all application amounts. Cannot exceed the payment amount."}]},{"heading":"Payment Methods","items":[{"label":"Cash","value":"Physical currency received from the customer."},{"label":"Check","value":"Paper check. Use Reference Number to record the check number."},{"label":"Credit Card","value":"Card payment. Reference Number can hold the last four digits or transaction ID."},{"label":"Bank Transfer","value":"ACH or direct bank transfer. Reference Number can hold the transfer confirmation."},{"label":"Wire","value":"Wire transfer. Reference Number holds the wire confirmation number."},{"label":"Other","value":"Any payment method not covered above. Use Notes to describe."}]},{"heading":"Table Columns (Payments List)","items":[{"label":"Payment #","value":"Sortable. Auto-generated payment number displayed in monospace font. Width: 120px."},{"label":"Customer","value":"Sortable. Customer name from the linked customer record."},{"label":"Method","value":"Sortable, filterable (enum). Payment method label (Cash, Check, Credit Card, etc.). Width: 100px."},{"label":"Amount","value":"Sortable, right-aligned. Total payment amount formatted as currency. Width: 100px."},{"label":"Applied","value":"Sortable, right-aligned. Sum of all invoice applications formatted as currency. Width: 100px."},{"label":"Unapplied","value":"Sortable, right-aligned. Payment amount minus applied amount. Highlighted in yellow (text-warning class) when greater than $0.00. Width: 100px."},{"label":"Date","value":"Sortable, date type. Payment date formatted MM/dd/yyyy. Width: 110px."},{"label":"Reference #","value":"Sortable. Reference number text, or '---' when empty. Width: 120px."},{"label":"Created","value":"Sortable, date type. Record creation date formatted MM/dd/yyyy. Width: 110px."}]},{"heading":"Detail Dialog / Detail Panel Fields","items":[{"label":"Payment Number","value":"Display only. Auto-generated identifier shown in the detail header alongside the payments icon."},{"label":"Customer","value":"Display with entity link. Clickable to navigate to customer detail."},{"label":"Method","value":"Display only. Translated payment method label."},{"label":"Payment Date","value":"Display only. Formatted MM/dd/yyyy."},{"label":"Reference Number","value":"Display only. Shown conditionally — hidden when empty."},{"label":"Amount","value":"Display only. Total payment amount as currency."},{"label":"Applied","value":"Display only. Total applied across all invoice applications."},{"label":"Unapplied","value":"Display only. Highlighted in yellow when greater than $0.00."},{"label":"Notes","value":"Display only. Shown conditionally — hidden when empty."},{"label":"Applications table","value":"Lists all invoice applications with Invoice Number (monospace) and Amount (currency). Includes application count in section header."},{"label":"Created / Updated","value":"Display only. Record timestamps formatted MM/dd/yyyy."},{"label":"Activity History","value":"Entity activity section showing payment history timeline."}]},{"heading":"Buttons and Actions","items":[{"label":"Record Payment (primary button, page header)","value":"Opens the create payment dialog. Only visible in standalone mode. data-testid: new-payment-btn"},{"label":"Create Payment (primary button, dialog footer)","value":"Saves the new payment and its invoice applications. Disabled when form is invalid or save is in progress. Shows validation popover on hover when disabled. data-testid: payment-save-btn"},{"label":"Cancel (dialog footer)","value":"Closes the create dialog without saving."},{"label":"Close (detail panel, X icon)","value":"Closes the detail dialog/panel."},{"label":"Delete (detail panel, danger button)","value":"Deletes the payment after confirmation. Only visible when the payment has zero applications. Opens a confirmation dialog with danger severity. Soft-deletes the record."},{"label":"Row click","value":"Opens the payment detail dialog showing all fields, applications table, activity history, and delete action."}]},{"heading":"Validation Rules","items":[{"label":"Customer","value":"Required. Must select a valid customer from the dropdown."},{"label":"Payment Method","value":"Required. Must select one of the six methods."},{"label":"Amount","value":"Required. Must be greater than $0.00."},{"label":"Payment Date","value":"Required. Must select a valid date."},{"label":"Application amounts","value":"Each application must be greater than $0.00. Individual application cannot exceed the target invoice's remaining balance."},{"label":"Total applied","value":"Sum of all application amounts cannot exceed the payment amount."},{"label":"Delete restriction","value":"A payment can only be deleted if it has no invoice applications. Payments with applications must have their applications removed first."},{"label":"Submit button popover","value":"When form is invalid, hovering over Create Payment shows a validation popover listing which fields need attention."}]},{"heading":"Accounting Boundary Behavior","items":[{"label":"Standalone mode","value":"Full CRUD: create, view details, delete (if no applications). Record Payment button visible. All fields editable in create dialog."},{"label":"Integrated mode","value":"Read-only. Blue banner shows 'Payments are managed by [provider]'. Record Payment button hidden. Data syncs from accounting provider. Detail view available but no create/delete actions."},{"label":"Banner location","value":"Appears between page header and content area when an accounting provider is connected."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payments Knowledge Check",
            Slug = "payments-quiz",
            Summary = "Test your knowledge of the Payments module: methods, invoice applications, standalone vs integrated mode, validation, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/payments"]""",
            Tags = """["payments","quiz","accounting"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pmt1","text":"A customer mails you a check for $5,000 that covers two invoices. How do you record this in QB Engineer?","options":[{"id":"a","text":"Create two separate payments of $2,500 each, one for each invoice"},{"id":"b","text":"Click Record Payment, enter $5,000 with method Check, then add two invoice applications splitting the amount across both invoices","isCorrect":true},{"id":"c","text":"Go to each invoice and mark it as Paid, then create a payment for the total"},{"id":"d","text":"Create one payment and leave it unapplied — the system will match invoices automatically"}],"explanation":"A single payment can be applied to multiple invoices. Create one payment for $5,000, select Check as the method, then use the Invoice Applications section to add each invoice with its respective portion of the payment."},{"id":"pmt2","text":"You see a yellow 'Unapplied' amount of $1,200 on a payment row in the table. What does this mean?","options":[{"id":"a","text":"The payment failed to process and $1,200 was returned"},{"id":"b","text":"$1,200 of the payment has not been applied to any invoice yet","isCorrect":true},{"id":"c","text":"The customer still owes $1,200 on the payment"},{"id":"d","text":"$1,200 was applied to an invoice that was later voided"}],"explanation":"Unapplied amount means that portion of the payment has not been linked to any invoice. The yellow highlight draws attention to money received but not yet accounted for against specific invoices."},{"id":"pmt3","text":"What happens to an invoice when a payment application fully covers its remaining balance?","options":[{"id":"a","text":"The invoice is deleted from the system"},{"id":"b","text":"The invoice status automatically changes to Paid","isCorrect":true},{"id":"c","text":"Nothing — you must manually mark the invoice as Paid"},{"id":"d","text":"The invoice is archived and hidden from the list"}],"explanation":"When a payment application covers an invoice's full remaining balance, the system automatically sets the invoice status to Paid. For partial applications, the invoice moves to Partially Paid."},{"id":"pmt4","text":"Your shop just connected QuickBooks Online. What happens to the Payments page?","options":[{"id":"a","text":"Nothing changes — payments are always managed locally"},{"id":"b","text":"A blue banner appears indicating payments are managed by QuickBooks, the Record Payment button is hidden, and data becomes read-only","isCorrect":true},{"id":"c","text":"All existing payment records are deleted and replaced with QuickBooks data"},{"id":"d","text":"The Payments page is completely removed from the navigation"}],"explanation":"Payments is an accounting-bounded feature. When an accounting provider is connected, the module switches to read-only mode with a banner explaining that payments are managed by the provider. Existing data is preserved, and new data syncs from QuickBooks."},{"id":"pmt5","text":"You want to delete a payment, but the Delete button is not visible in the detail panel. Why?","options":[{"id":"a","text":"You don't have the Admin role required to delete payments"},{"id":"b","text":"The payment has one or more invoice applications — you must remove all applications before deleting","isCorrect":true},{"id":"c","text":"Payments can never be deleted, only archived"},{"id":"d","text":"The payment was synced from an accounting provider and cannot be modified locally"}],"explanation":"A payment can only be deleted when it has zero invoice applications. This prevents orphaned invoice status changes. Remove all applications first, then the Delete button will appear."},{"id":"pmt6","text":"A customer pays $3,000 by wire transfer, but you haven't created the invoice yet. How should you handle this?","options":[{"id":"a","text":"Wait until the invoice is created before recording the payment"},{"id":"b","text":"Record the payment with method Wire and $3,000 amount, but don't add any invoice applications — the unapplied amount will track the unmatched funds","isCorrect":true},{"id":"c","text":"Create a placeholder invoice for $3,000, then immediately apply the payment to it"},{"id":"d","text":"Record it as a Note on the customer record instead of a payment"}],"explanation":"You can record a payment without applying it to any invoice. The full amount shows as Unapplied (highlighted yellow in the table), making it easy to find and apply later once the invoice is created."},{"id":"pmt7","text":"What is the purpose of the Reference Number field on a payment?","options":[{"id":"a","text":"It is the auto-generated payment number used as the primary identifier"},{"id":"b","text":"It records an external reference like a check number, wire confirmation, or transaction ID","isCorrect":true},{"id":"c","text":"It links the payment to a sales order number"},{"id":"d","text":"It is required for all payment methods except Cash"}],"explanation":"Reference Number is an optional field for recording external identifiers — check numbers, wire confirmations, credit card transaction IDs, or ACH references. It's searchable from the payments list. The auto-generated Payment # is a separate field."},{"id":"pmt8","text":"You try to apply $2,000 of a payment to an invoice that only has a $1,500 remaining balance. What happens?","options":[{"id":"a","text":"The system accepts it and creates a $500 credit on the invoice"},{"id":"b","text":"The system rejects it — the application amount cannot exceed the invoice's remaining balance","isCorrect":true},{"id":"c","text":"The system applies $1,500 and leaves $500 unapplied automatically"},{"id":"d","text":"The system accepts it but flags the invoice as overpaid"}],"explanation":"The server validates that each application amount does not exceed the target invoice's remaining balance. If the amount is too high, the request is rejected with an error message showing the invoice number and its actual balance."},{"id":"pmt9","text":"Which of the following is NOT a supported payment method in QB Engineer?","options":[{"id":"a","text":"Bank Transfer"},{"id":"b","text":"Wire"},{"id":"c","text":"PayPal","isCorrect":true},{"id":"d","text":"Other"}],"explanation":"The six supported payment methods are Cash, Check, Credit Card, Bank Transfer, Wire, and Other. PayPal or any non-listed method should be recorded using the Other method, with details in the Notes field."},{"id":"pmt10","text":"You need to find all Check payments from a specific customer. What's the fastest approach?","options":[{"id":"a","text":"Export the payments to CSV and filter in Excel"},{"id":"b","text":"Type the customer name in the Search box and select Check from the Method filter dropdown","isCorrect":true},{"id":"c","text":"Go to the customer detail page and look at their payment history tab"},{"id":"d","text":"Use the Reports module to build a custom payment report"}],"explanation":"The Payments list page has both a text search (filters by payment number, customer name, or reference number) and a Method filter dropdown. Combining these two filters — searching for the customer name and selecting Check — gives you the exact results you need instantly."}]}"""
        });

        Log.Information("Seeded Payments training modules");
    }
}
